            failedChecks.append("reverse_engineering_tools")
        }
        
        let level: IntegrityLevel
        switch failedChecks.count {
        case 0:
            level = .trusted
        case 1...2:
            level = .suspicious
        default:
            level = .compromised
        }
        
        let checksumData = failedChecks.joined(separator: "|").data(using: .utf8)!
        let checksum = SHA256.hash(data: checksumData).compactMap { String(format: "%02x", $0) }.joined()
        
        return IntegrityReport(
            level: level,
            failedChecks: failedChecks,
            timestamp: Date(),
