// MARK: - Secure Storage

final class SecureKeychain {
    
    enum KeychainError: Error {
        case duplicateItem
        case itemNotFound
        case unexpectedStatus(OSStatus)
        case dataConversionError
        case deviceCompromised
    }
    
    private static let accessGroup = "com.securetrade.shared"
    
    static func store(key: String, data: Data, requireBiometric: Bool = false) throws {
        // Verify device integrity before storing sensitive data
        let integrity = DeviceIntegrityChecker.performFullIntegrityCheck()
        guard integrity.level != .compromised else {
            throw KeychainError.deviceCompromised
        }
        
        var accessControl: SecAccessControl?
        if requireBiometric {
            var error: Unmanaged<CFError>?
            accessControl = SecAccessControlCreateWithFlags(
                kCFAllocatorDefault,
                kSecAttrAccessibleWhenPasscodeSetThisDeviceOnly,
                [.biometryCurrentSet, .privateKeyUsage],
                &error
            )
            if error != nil {
                throw KeychainError.unexpectedStatus(errSecParam)
            }
        }
        
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenPasscodeSetThisDeviceOnly
        ]
        
        if let ac = accessControl {
            query[kSecAttrAccessControl as String] = ac
        }
        
        // Delete existing item first
        SecItemDelete(query as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw KeychainError.unexpectedStatus(status)
        }
    }
    
    static func retrieve(key: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            if status == errSecItemNotFound {
                throw KeychainError.itemNotFound
            }
            throw KeychainError.unexpectedStatus(status)
        }
        
        return data
    }
    
    static func delete(key: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw KeychainError.unexpectedStatus(status)
        }
    }
}

// MARK: - Secure API Communication

final class SecureAPIClient {
    
    enum APIError: Error {
        case deviceCompromised
        case invalidResponse
        case authenticationFailed
        case networkError(Error)
        case serverError(Int, String)
        case certificatePinningFailed
        case rateLimited
        case encryptionError
    }
    
    private let session: URLSession
    private let baseURL: URL
    private let pinnedCertificateHashes: Set<String>
    private var authToken: String?
    private let requestQueue = DispatchQueue(label: "com.securetrade.api", qos: .userInitiated)
    private var requestTimestamps: [Date] = []
    private let maxRequestsPerMinute = 60
    
    init(baseURL: URL, pinnedCertHashes: Set<String>) {
        self.baseURL = baseURL
        self.pinnedCertificateHashes = pinnedCertHashes
        
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "X-Platform": "iOS",
            "X-App-Version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown"
        ]
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        
        let delegate = CertificatePinningDelegate(pinnedHashes: pinnedCertHashes)
        self.session = URLSession(configuration: config, delegate: delegate, delegateQueue: nil)
    }
    
    func setAuthToken(_ token: String) {
        self.authToken = token
    }
    
    private func checkRateLimit() throws {
        let now = Date()
        requestTimestamps = requestTimestamps.filter { now.timeIntervalSince($0) < 60 }
        guard requestTimestamps.count < maxRequestsPerMinute else {
            throw APIError.rateLimited
        }
        requestTimestamps.append(now)
    }
    
    func executeRequest<T: Decodable>(
        endpoint: String,
        method: String = "GET",
        body: Encodable? = nil,
        requiresIntegrity: Bool = true
    ) async throws -> T {
        // Rate limiting
        try checkRateLimit()
        
        // Device integrity check for sensitive operations
        if requiresIntegrity {
            let integrity = DeviceIntegrityChecker.performFullIntegrityCheck()
            if integrity.level == .compromised {
                throw APIError.deviceCompromised
            }
        }
        
        var request = URLRequest(url: baseURL.appendingPathComponent(endpoint))
        request.httpMethod = method
        
        // Add auth token
        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        // Add request nonce for replay protection
        let nonce = UUID().uuidString
        let timestamp = String(Int(Date().timeIntervalSince1970))
        request.setValue(nonce, forHTTPHeaderField: "X-Request-Nonce")
        request.setValue(timestamp, forHTTPHeaderField: "X-Request-Timestamp")
        
        // Sign request
        let signaturePayload = "\(method)|\(endpoint)|\(nonce)|\(timestamp)"
        let signature = computeHMAC(message: signaturePayload)
        request.setValue(signature, forHTTPHeaderField: "X-Request-Signature")
        
        // Add device integrity level
        let integrity = DeviceIntegrityChecker.performFullIntegrityCheck()
        request.setValue(String(describing: integrity.level), forHTTPHeaderField: "X-Device-Integrity")
        request.setValue(integrity.checksum, forHTTPHeaderField: "X-Integrity-Checksum")
        
        if let body = body {
            let encoder = JSONEncoder()
            encoder.dateEncodingStrategy = .iso8601
            request.httpBody = try encoder.encode(AnyEncodable(body))
        }
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            let decoder = JSONDecoder()
            decoder.dateDecodingStrategy = .iso8601
            return try decoder.decode(T.self, from: data)
        case 401:
            throw APIError.authenticationFailed
        case 429:
            throw APIError.rateLimited
        default:
            let message = String(data: data, encoding: .utf8) ?? "Unknown error"
            throw APIError.serverError(httpResponse.statusCode, message)
        }
    }
    
    private func computeHMAC(message: String) -> String {
        guard let secretData = try? SecureKeychain.retrieve(key: "api_hmac_secret"),
              let messageData = message.data(using: .utf8) else {
            return ""
        }
        
        let key = SymmetricKey(data: secretData)
        let signature = HMAC<SHA256>.authenticationCode(for: messageData, using: key)
        return Data(signature).base64EncodedString()
    }
}

// MARK: - Certificate Pinning Delegate

final class CertificatePinningDelegate: NSObject, URLSessionDelegate {
    
    private let pinnedHashes: Set<String>
    
    init(pinnedHashes: Set<String>) {
        self.pinnedHashes = pinnedHashes
    }
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Evaluate server trust
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        guard isValid else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Pin certificate
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        var pinningSucceeded = false
        
        for i in 0..<certificateCount {
            if let certificate = SecTrustGetCertificateAtIndex(serverTrust, i) {
                let certData = SecCertificateCopyData(certificate) as Data
                let hash = SHA256.hash(data: certData)
                let hashString = hash.compactMap { String(format: "%02x", $0) }.joined()
                
                if pinnedHashes.contains(hashString) {
                    pinningSucceeded = true
                    break
                }
            }
        }
        
        if pinningSucceeded {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

// MARK: - Trading Models

struct Stock: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    let exchange: String
    var currentPrice: Decimal
    var previousClose: Decimal
    var dayHigh: Decimal
    var dayLow: Decimal
    var volume: Int64
    var lastUpdated: Date
    
    var changeAmount: Decimal {
        currentPrice - previousClose
    }
    
    var changePercent: Decimal {
        guard previousClose != 0 else { return 0 }
        return (changeAmount / previousClose) * 100
    }
}

enum OrderType: String, Codable {
    case market = "MARKET"
    case limit = "LIMIT"
    case stopLoss = "STOP_LOSS"
    case stopLimit = "STOP_LIMIT"
    case trailingStop = "TRAILING_STOP"
}

