// MARK: - Trade Validation

final class TradeValidator {
    
    enum ValidationError: Error, LocalizedError {
        case insufficientFunds(required: Decimal, available: Decimal)
        case insufficientShares(required: Decimal, available: Decimal)
        case invalidQuantity
        case invalidPrice
        case marketClosed
        case symbolNotFound
        case orderTooLarge(maxQuantity: Decimal)
        case priceOutOfRange
        case deviceIntegrityFailed
        case patternDayTraderRestriction
        
        var errorDescription: String? {
            switch self {
            case .insufficientFunds(let required, let available):
                return "Insufficient funds. Required: \(required), Available: \(available)"
            case .insufficientShares(let required, let available):
                return "Insufficient shares. Required: \(required), Available: \(available)"
            case .invalidQuantity:
                return "Invalid order quantity. Must be greater than 0."
            case .invalidPrice:
                return "Invalid price specified."
            case .marketClosed:
                return "Market is currently closed."
            case .symbolNotFound:
                return "Stock symbol not found."
            case .orderTooLarge(let max):
                return "Order exceeds maximum quantity of \(max)."
            case .priceOutOfRange:
                return "Price is outside acceptable range."
            case .deviceIntegrityFailed:
                return "Trading is restricted on this device for security reasons."
            case .patternDayTraderRestriction:
                return "Pattern day trader restriction applies."
            }
        }
    }
    
    private let maxOrderQuantity: Decimal = 100000
    private let priceTolerancePercent: Decimal = 10 // 10% from current price
    
    func validateOrder(
        request: OrderRequest,
        portfolio: Portfolio,
        currentPrice: Decimal,
        isMarketOpen: Bool
    ) throws {
        // Device integrity check - critical for trade execution
        let integrity = DeviceIntegrityChecker.performFullIntegrityCheck()
        guard integrity.level != .compromised else {
            throw ValidationError.deviceIntegrityFailed
        }
        
        // Basic validations
        guard request.quantity > 0 else {
            throw ValidationError.invalidQuantity
        }
        
        guard request.quantity <= maxOrderQuantity else {
            throw ValidationError.orderTooLarge(maxQuantity: maxOrderQuantity)
        }
        
        // Market hours check (allow limit orders outside market hours)
        if request.type == .market && !isMarketOpen {
            throw ValidationError.marketClosed
        }
        
        // Price validation for limit orders
        if let limitPrice = request.limitPrice {
            guard limitPrice > 0 else {
                throw ValidationError.invalidPrice
            }
            
            let tolerance = currentPrice * priceTolerancePercent / 100
            let minPrice = currentPrice - tolerance
            let maxPrice = currentPrice + tolerance
            
            guard limitPrice >= minPrice && limitPrice <= maxPrice else {
                throw ValidationError.priceOutOfRange
            }
        }
        
        // Stop price validation
        if let stopPrice = request.stopPrice {
            guard stopPrice > 0 else {
                throw ValidationError.invalidPrice
            }
        }
        
        // Funds/shares check
        switch request.side {
        case .buy:
            let estimatedCost: Decimal
            if let limitPrice = request.limitPrice {
                estimatedCost = limitPrice * request.quantity
            } else {
                estimatedCost = currentPrice * request.quantity
            }
            
            guard portfolio.buyingPower >= estimatedCost else {
                throw ValidationError.insufficientFunds(
                    required: estimatedCost,
                    available: portfolio.buyingPower
                )
            }
            
        case .sell:
            let position = portfolio.positions.first { $0.symbol == request.symbol }
            let availableShares = position?.quantity ?? 0
            
            guard availableShares >= request.quantity else {
                throw ValidationError.insufficientShares(
                    required: request.quantity,
                    available: availableShares
                )
            }
        }
    }
}

// MARK: - Biometric Authentication

final class BiometricAuthenticator {
    
    enum BiometricError: Error {
        case notAvailable
        case authenticationFailed
        case userCancelled
        case deviceCompromised
    }
    
    static func authenticate(reason: String) async throws -> Bool {
        // Check device integrity before biometric auth
        let integrity = DeviceIntegrityChecker.performFullIntegrityCheck()
        guard integrity.level != .compromised else {
            throw BiometricError.deviceCompromised
        }
        
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        context.localizedFallbackTitle = "Use Passcode"
        
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            throw BiometricError.notAvailable
        }
        
        return try await withCheckedThrowingContinuation { continuation in
            context.evaluatePolicy(
                .deviceOwnerAuthenticationWithBiometrics,
                localizedReason: reason
            ) { success, error in
                if success {
                    continuation.resume(returning: true)
                } else if let error = error as? LAError {
                    switch error.code {
                    case .userCancel, .appCancel:
                        continuation.resume(throwing: BiometricError.userCancelled)
                    default:
                        continuation.resume(throwing: BiometricError.authenticationFailed)
                    }
                } else {
                    continuation.resume(throwing: BiometricError.authenticationFailed)
                }
            }
        }
    }
}

