        let report = DeviceIntegrityChecker.performFullIntegrityCheck()
        deviceIntegrityLevel = report.level
        
        switch report.level {
        case .compromised:
            tradingRestricted = true
            errorMessage = "Trading is restricted on this device due to security concerns. Please use a secure device."
        case .suspicious:
            // Allow read-only access, restrict trading
            tradingRestricted = false // Allow with additional verification
            errorMessage = "Security warning: Some device integrity checks failed. Additional verification may be required for trades."
        case .trusted:
            tradingRestricted = false
        }
    }
    
    private func startPeriodicIntegrityChecks() {
        integrityCheckTimer = Timer.scheduledTimer(withTimeInterval: 300, repeats: true) { [weak self] _ in
            Task { @MainActor [weak self] in
                self?.performInitialIntegrityCheck()
            }
        }
    }
    
    private func requireIntegrityForTrading() throws {
        let report = DeviceIntegrityChecker.performFullIntegrityCheck()
        if report.level == .compromised {
            throw TradeValidator.ValidationError.deviceIntegrityFailed
        }
    }
    
