        isLoading = true
        errorMessage = nil
        
        do {
            let response: APIResponse<Portfolio> = try await apiClient.executeRequest(
                endpoint: "/api/v1/portfolio",
                requiresIntegrity: true
            )
            
            if let data = response.data {
                portfolio = data
            } else {
                errorMessage = response.error ?? "Failed to load portfolio"
            }
        } catch let error as SecureAPIClient.APIError {
            handleAPIError(error)
        } catch {
            errorMessage = "Network error: \(error.localizedDescription)"
        }
        
        isLoading = false
    }
    
    func loadOpenOrders() async {
        do {
            let response: APIResponse<[TradeOrder]> = try await apiClient.executeRequest(
                endpoint: "/api/v1/orders?status=open",
                requiresIntegrity: true
            )
            
            if let data = response.data {
                openOrders = data
            }
        } catch {
            errorMessage = "Failed to load orders: \(error.localizedDescription)"
        }
    }
    
    func loadOrderHistory() async {
        do {
            let response: APIResponse<[TradeOrder]> = try await apiClient.executeRequest(
                endpoint: "/api/v1/orders/history",
                requiresIntegrity: true
            )
            
            if let data = response.data {
                orderHistory = data
            }
        } catch {
            errorMessage = "Failed to load order history: \(error.localizedDescription)"
        }
    }
    
    // MARK: - Trade Execution
    
    func previewOrder(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Decimal,
        limitPrice: Decimal? = nil,
        stopPrice: Decimal? = nil,
        trailingPercent: Decimal? = nil,
        timeInForce: TimeInForce = .day
    ) async throws -> TradeConfirmation {
        // Multi-layer security check
        try requireIntegrityForTrading()
        
        guard let portfolio = portfolio else {
            throw TradeValidator.ValidationError.insufficientFunds(required: 0, available: 0)
        }
        
        // Get current price
        let stock = watchlist.first { $0.symbol == symbol }
        let currentPrice = stock?.currentPrice ?? 0
        
        let request = OrderRequest(
            symbol: symbol,
            side: side,
            type: type,
            quantity: quantity,
            limitPrice: limitPrice,
            stopPrice: stopPrice,
            trailingPercent: trailingPercent,
            timeInForce: timeInForce,
            clientOrderId: generateClientOrderId()
        )
        
        // Validate locally first
        try validator.validateOrder(
            request: request,
            portfolio: portfolio,
            currentPrice: currentPrice,
            isMarketOpen: isMarketOpen
        )
        
        // Get server-side preview
        let response: APIResponse<TradeConfirmation> = try await apiClient.executeRequest(
            endpoint: "/api/v1/orders/preview",
            method: "POST",
            body: request,
            requiresIntegrity: true
        )
        
        guard let confirmation = response.data else {
            throw SecureAPIClient.APIError.invalidResponse
        }
        
        return confirmation
    }
    
    func executeOrder(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Decimal,
        limitPrice: Decimal? = nil,
        stopPrice: Decimal? = nil,
        trailingPercent: Decimal? = nil,
        timeInForce: TimeInForce = .day
    ) async throws -> TradeOrder {
        // Critical operation - full integrity check
        try requireIntegrityForTrading()
        
        // Require biometric authentication for all trades
        let authenticated = try await BiometricAuthenticator.authenticate(
            reason: "Authenticate to execute \(side.rawValue) order for \(symbol)"
        )
        
        guard authenticated else {
            throw BiometricAuthenticator.BiometricError.authenticationFailed
        }
        
        // Additional integrity check after biometric (defense in depth)
        let postAuthIntegrity = DeviceIntegrityChecker.performFullIntegrityCheck()
        guard postAuthIntegrity.level != .compromised else {
            throw TradeValidator.ValidationError.deviceIntegrityFailed
        }
        
        guard let portfolio = portfolio else {
            throw TradeValidator.ValidationError.insufficientFunds(required: 0, available: 0)
        }
        
        let stock = watchlist.first { $0.symbol == symbol }
        let currentPrice = stock?.currentPrice ?? 0
        
        let clientOrderId = generateClientOrderId()
        
        let request = OrderRequest(
            symbol: symbol,
            side: side,
            type: type,
            quantity: quantity,
            limitPrice: limitPrice,
            stopPrice: stopPrice,
            trailingPercent: trailingPercent,
            timeInForce: timeInForce,
            clientOrderId: clientOrderId
        )
        
        // Final validation
        try validator.validateOrder(
            request: request,
            portfolio: portfolio,
            currentPrice: currentPrice,
            isMarketOpen: isMarketOpen
        )
        
        // Execute
        let response: APIResponse<TradeOrder> = try await apiClient.executeRequest(
            endpoint: "/api/v1/orders",
            method: "POST",
            body: request,
            requiresIntegrity: true
        )
        
        guard let order = response.data else {
            throw SecureAPIClient.APIError.invalidResponse
        }
        
        // Log trade for audit
        await logTradeExecution(order: order, integrityLevel: postAuthIntegrity.level)
        
        // Refresh portfolio
        await loadPortfolio()
        await loadOpenOrders()
        
        return order
    }
    
    func cancelOrder(orderId: String) async throws {
        try requireIntegrityForTrading()
        
        let authenticated = try await BiometricAuthenticator.authenticate(
            reason: "Authenticate to cancel order"
        )
        
        guard authenticated else {
            throw BiometricAuthenticator.BiometricError.authenticationFailed
        }
        
        let _: APIResponse<TradeOrder> = try await apiClient.executeRequest(
            endpoint: "/api/v1/orders/\(orderId)/cancel",
            method: "POST",
            requiresIntegrity: true
        )
        
        await loadOpenOrders()
        await loadPortfolio()
    }
    
    func modifyOrder(
        orderId: String,
        newQuantity: Decimal? = nil,
        newLimitPrice: Decimal? = nil,
        newStopPrice: Decimal? = nil
    ) async throws -> TradeOrder {
        try requireIntegrityForTrading()
        
        let authenticated = try await BiometricAuthenticator.authenticate(
            reason: "Authenticate to modify order"
        )
        
        guard authenticated else {
            throw BiometricAuthenticator.BiometricError.authenticationFailed
        }
        
        struct ModifyRequest: Codable {
            let quantity: Decimal?
            let limitPrice: Decimal?
            let stopPrice: Decimal?
        }
        
        let modifyRequest = ModifyRequest(
            quantity: newQuantity,
            limitPrice: newLimitPrice,
            stopPrice: newStopPrice
        )
        
        let response: APIResponse<TradeOrder> = try await apiClient.executeRequest(
            endpoint: "/api/v1/orders/\(orderId)",
            method: "PATCH",
            body: modifyRequest,
            requiresIntegrity: true
        )
        
        guard let order = response.data else {
            throw SecureAPIClient.APIError.invalidResponse
        }
        
        await loadOpenOrders()
        return order
    }
    
    // MARK: - Market Data
    
    func loadWatchlist() async {
        do {
            let response: APIResponse<[Stock]> = try await apiClient.executeRequest(
                endpoint: "/api/v1/watchlist",
                requiresIntegrity: false
            )
            
            if let data = response.data {
                watchlist = data
            }
        } catch {
            errorMessage = "Failed to load watchlist: \(error.localizedDescription)"
        }
    }
    
    func getQuote(symbol: String) async throws -> Stock {
        let response: APIResponse<Stock> = try await apiClient.executeRequest(
            endpoint: "/api/v1/quotes/\(symbol)",
            requiresIntegrity: false
        )
        
        guard let stock = response.data else {
            throw TradeValidator.ValidationError.symbolNotFound
        }
        
        return stock
    }
    
    func startRealTimePriceUpdates() {
        priceUpdateTimer = Timer.scheduledTimer(withTimeInterval: 5.0, repeats: true) { [weak self] _ in
            Task { @MainActor [weak self] in
                await self?.refreshPrices()
            }
        }
    }
    
    func stopRealTimePriceUpdates() {
        priceUpdateTimer?.invalidate()
        priceUpdateTimer = nil
    }
    
    private func refreshPrices() async {
        let symbols = watchlist.map { $0.symbol }.joined(separator: ",")
        guard !symbols.isEmpty else { return }
        
        do {
            let response: APIResponse<[Stock]> = try await apiClient.executeRequest(
                endpoint: "/api/v1/quotes/batch?symbols=\(symbols)",
                requiresIntegrity: false
            )
            
            if let updatedStocks = response.data {
                for updated in updatedStocks {
                    if let index = watchlist.firstIndex(where: { $0.symbol == updated.symbol }) {
                        watchlist[index] = updated
                    }
                }
            }
        } catch {
            // Silently fail for price updates - non-critical
        }
    }
    
    func checkMarketStatus() async {
        struct MarketStatus: Codable {
            let isOpen: Bool
            let nextOpen: Date?
            let nextClose: Date?
        }
        
        do {
            let response: APIResponse<MarketStatus> = try await apiClient.executeRequest(
                endpoint: "/api/v1/market/status",
                requiresIntegrity: false
            )
            
            if let status = response.data {
                isMarketOpen = status.isOpen
            }
        } catch {
            // Default to closed if we can't check
            isMarketOpen = false
        }
    }
    
    // MARK: - Helpers
    
    private func generateClientOrderId() -> String {
        let timestamp = Int(Date().timeIntervalSince1970 * 1000)
        let random = UUID().uuidString.prefix(8)
        return "iOS-\(timestamp)-\(random)"
    }
    
    private func logTradeExecution(order: TradeOrder, integrityLevel: DeviceIntegrityChecker.IntegrityLevel) async {
        struct TradeAuditLog: Codable {
            let orderId: String
            let clientOrderId: String
            let integrityLevel: String
            let timestamp: Date
            let deviceModel: String
            let osVersion: String
        }
        
        let log = TradeAuditLog(
            orderId: order.id,
            clientOrderId: order.clientOrderId,
            integrityLevel: String(describing: integrityLevel),
            timestamp: Date(),
            deviceModel: UIDevice.current.model,
            osVersion: UIDevice.current.systemVersion
        )
        
        do {
            let _: APIResponse<EmptyResponse> = try await apiClient.executeRequest(
                endpoint: "/api/v1/audit/trade",
                method: "POST",
                body: log,
                requiresIntegrity: false
            )
        } catch {
            // Audit logging failure should not block trading
        }
    }
    
    private func handleAPIError(_ error: SecureAPIClient.APIError) {
        switch error {
        case .deviceCompromised:
            errorMessage = "Trading is restricted on this device for security reasons."
            tradingRestricted = true
        case .authenticationFailed:
            errorMessage = "Authentication failed. Please log in again."
        case .rateLimited:
            errorMessage = "Too many requests. Please wait a moment."
        case .certificatePinningFailed:
            errorMessage = "Secure connection could not be established."
        case .serverError(let code, let message):
            errorMessage = "Server error (\(code)): \(message)"
        case .networkError(let underlying):
            errorMessage = "Network error: \(underlying.localizedDescription)"
        default:
            errorMessage = "An unexpected error occurred."
        }
    }
}

// MARK: - Session Manager

final class SecureSessionManager {
    
    static let shared = SecureSessionManager()
    
    private let tokenKey = "auth_token"
    private let refreshTokenKey = "refresh_token"
    private let tokenExpiryKey = "token_expiry"
    
    private init() {}
    
    var isAuthenticated: Bool {
        guard let _ = try? SecureKeychain.retrieve(key: tokenKey) else {
            return false
        }
        return !isTokenExpired
    }
    
    private var isTokenExpired: Bool {
        guard let expiryData = try? SecureKeychain.retrieve(key: tokenExpiryKey),
              let expiryString = String(data: expiryData, encoding: .utf8),
              let expiryTimestamp = Double(expiryString) else {
            return true
        }
        return Date().timeIntervalSince1970 > expiryTimestamp
    }
    
    func login(username: String, password: String, apiClient: SecureAPIClient) async throws {
        // Check device integrity before login
        let integrity = DeviceIntegrityChecker.performFullIntegrityCheck()
        guard integrity.level != .compromised else {
            throw SecureAPIClient.APIError.deviceCompromised
        }
        
        struct LoginRequest: Codable {
            let username: String
            let password: String
            let deviceIntegrity: String
        }
        
        struct LoginResponse: Codable {
            let accessToken: String
            let refreshToken: String
            let expiresIn: Int
        }
        
        let request = LoginRequest(
            username: username,
            password: password,
            deviceIntegrity: String(describing: integrity.level)
        )
        
        let response: APIResponse<LoginResponse> = try await apiClient.executeRequest(
            endpoint: "/api/v1/auth/login",
            method: "POST",
            body: request,
            requiresIntegrity: true
        )
        
        guard let loginData = response.data else {
            throw SecureAPIClient.APIError.authenticationFailed
        }
        
        // Store tokens securely with biometric protection
        try SecureKeychain.store(
            key: tokenKey,
            data: loginData.accessToken.data(using: .utf8)!,
            requireBiometric: true
        )
        
        try SecureKeychain.store(
            key: refreshTokenKey,
            data: loginData.refreshToken.data(using: .utf8)!,
            requireBiometric: true
        )
        
        let expiry = Date().timeIntervalSince1970 + Double(loginData.expiresIn)
        try SecureKeychain.store(
            key: tokenExpiryKey,
            data: String(expiry).data(using: .utf8)!
        )
        
        apiClient.setAuthToken(loginData.accessToken)
    }
    
    func logout() {
        try? SecureKeychain.delete(key: tokenKey)
        try? SecureKeychain.delete(key: refreshTokenKey)
        try? SecureKeychain.delete(key: tokenExpiryKey)
    }
    
    func getAccessToken() throws -> String {
        let data = try SecureKeychain.retrieve(key: tokenKey)
        guard let token = String(data: data, encoding: .utf8) else {
            throw SecureKeychain.KeychainError.dataConversionError
        }
        return token
    }
}

// MARK: - WebSocket for Real-Time Data

final class SecureWebSocketManager: NSObject, URLSessionWebSocketDelegate {
    
    typealias PriceUpdateHandler = (String, Decimal) -> Void
    typealias OrderUpdateHandler = (TradeOrder) -> Void
    
    private var webSocketTask: URLSessionWebSocketTask?
    private var session: URLSession?
    private let url: URL
    private var isConnected = false
    private var reconnectAttempts = 0
    private let maxReconnectAttempts = 5
    
    var onPriceUpdate: PriceUpdateHandler?
    var onOrderUpdate: OrderUpdateHandler?
    
    init(url: URL) {
        self.url = url
        super.init()
    }
    
    func connect(authToken: String) {
        // Integrity check before establishing WebSocket
        let integrity = DeviceIntegrityChecker.performFullIntegrityCheck()
        guard integrity.level != .compromised else { return }
        
        let config = URLSessionConfiguration.default
        config.httpAdditionalHeaders = [
            "Authorization": "Bearer \(authToken)"
        ]
        
        session = URLSession(configuration: config, delegate: self, delegateQueue: nil)
        webSocketTask = session?.webSocketTask(with: url)
        webSocketTask?.resume()
        
        receiveMessage()
    }
    
    func disconnect() {
        webSocketTask?.cancel(with: .goingAway, reason: nil)
        isConnected = false
    }
    
    func subscribe(symbols: [String]) {
        struct SubscribeMessage: Codable {
            let action: String
            let symbols: [String]
        }
        
        let message = SubscribeMessage(action: "subscribe", symbols: symbols)
        
        guard let data = try? JSONEncoder().encode(message) else { return }
        
        webSocketTask?.send(.data(data)) { error in
            if let error = error {
                print("WebSocket send error: \(error)")
            }
        }
    }
    
    private func receiveMessage() {
        webSocketTask?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .data(let data):
                    self?.handleMessage(data: data)
                case .string(let text):
                    if let data = text.data(using: .utf8) {
                        self?.handleMessage(data: data)
                    }
                @unknown default:
                    break
                }
                // Continue receiving
                self?.receiveMessage()
                
            case .failure(let error):
                print("WebSocket receive error: \(error)")
                self?.handleDisconnection()
            }
        }
    }
    
    private func handleMessage(data: Data) {
        struct WSMessage: Codable {
            let type: String
            let symbol: String?
            let price: Decimal?
            let order: TradeOrder?
        }
        
        guard let message = try? JSONDecoder().decode(WSMessage.self, from: data) else { return }
        
        switch message.type {
        case "price_update":
            if let symbol = message.symbol, let price = message.price {
                onPriceUpdate?(symbol, price)
            }
        case "order_update":
            if let order = message.order {
                onOrderUpdate?(order)
            }
        default:
            break
        }
    }
    
    private func handleDisconnection() {
        isConnected = false
        
        guard reconnectAttempts < maxReconnectAttempts else { return }
        
        reconnectAttempts += 1
        let delay = Double(min(reconnectAttempts * 2, 30))
        
        DispatchQueue.main.asyncAfter(deadline: .now() + delay) { [weak self] in
            guard let self = self else { return }
            if let token = try? SecureSessionManager.shared.getAccessToken() {
                self.connect(authToken: token)
            }
        }
    }
    
    // URLSessionWebSocketDelegate
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didOpenWithProtocol protocol: String?) {
        isConnected = true
        reconnectAttempts = 0
    }
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didCloseWith closeCode: URLSessionWebSocketTask.CloseCode, reason: Data?) {
        handleDisconnection()
    }
}

