                Text(formatCurrency(stock.currentPrice))
                    .fontWeight(.semibold)
                
                HStack(spacing: 4) {
                    Image(systemName: stock.changeAmount >= 0 ? "arrow.up.right" : "arrow.down.right")
                        .font(.caption2)
                    Text("\(formatCurrency(abs(stock.changeAmount))) (\(formatPercent(abs(stock.changePercent))))")
                }
                .font(.caption)
                .foregroundColor(stock.changeAmount >= 0 ? .green : .red)
            }
        }
        .padding(.vertical, 4)
    }
}

